import React from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import FigmaChat from '../components/FigmaChat';

export default function FigmaHome() {
    const { user } = useAuth();

    return (
        <div>
            <div className="logo-174"><div className="rectangle-982-175"></div></div>
            <div className="registration-185">
                {!user ? (
                    <Link to="/login" className="registration-14">
                        <p className="text-15">Регистрация</p>
                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none"><path d="M20 21V19C20 16.8 18.2 15 16 15H8C5.8 15 4 16.8 4 19V21" stroke="white" strokeWidth="2"/><circle cx="12" cy="7" r="4" stroke="white" strokeWidth="2"/></svg>
                    </Link>
                ) : (
                    <div className="registration-187"><p className="text-186">{user.username}</p></div>
                )}
            </div>
            <div className="player-91">
                <div className="player-92">
                    <div className="rectangle-133524-93"></div>
                    <video controls style={{ width: '100%', display: 'block' }}><source src="https://sample-videos.com/video123/mp4/720/big_buck_bunny_720p_1mb.mp4" type="video/mp4" /></video>
                </div>
                <FigmaChat />
            </div>
        </div>
    );
}
